#include <vector>
#include <unordered_map>
using namespace std;

vector<int> twoSum(vector<int>& nums, int target) {
  unordered_map<int, int> seen;

  for (int i = 0; i < static_cast<int>(nums.size()); ++i) {
    int complement = target - nums[i];
    auto it = seen.find(complement);
    if (it != seen.end()) {
      return {it->second, i};
    }
    seen[nums[i]] = i;
  }

  return {};
}

