function isValid(s: string): boolean {
  const pairs: Record<string, string> = {")": "(", "]": "[", "}": "{"};
  const stack: string[] = [];

  for (const ch of s) {
    if (ch === "(" || ch === "[" || ch === "{") {
      stack.push(ch);
      continue;
    }

    const top = stack.length ? stack.pop() : undefined;
    if (top !== pairs[ch]) {
      return false;
    }
  }

  return stack.length === 0;
}

