#include <string>
#include <vector>
#include <unordered_map>
using namespace std;

bool isValid(const string& s) {
  unordered_map<char, char> pairs = {{')', '('}, {']', '['}, {'}', '{'}};
  vector<char> stack;

  for (char ch : s) {
    if (ch == '(' || ch == '[' || ch == '{') {
      stack.push_back(ch);
      continue;
    }

    if (stack.empty() || stack.back() != pairs[ch]) {
      return false;
    }
    stack.pop_back();
  }

  return stack.empty();
}

